pageStyles:
* { margin: 0; padding: 0; box-sizing: border-box; }

  @keyframes fadeInUp {
    from { opacity: 0; transform: translateY(30px); }
    to { opacity: 1; transform: translateY(0); }
  }
  @keyframes slideInRight {
    from { transform: translateX(20px); opacity: 0; }
    to { transform: translateX(0); opacity: 1; }
  }

  .anim-fade-up { animation: fadeInUp 0.8s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards; }
  .delay-100 { animation-delay: 0.1s; opacity: 0; }
  .delay-200 { animation-delay: 0.2s; opacity: 0; }
  .delay-300 { animation-delay: 0.3s; opacity: 0; }
  .delay-400 { animation-delay: 0.4s; opacity: 0; }

  .btn-gold-slide {
    position: relative;
    overflow: hidden;
    z-index: 1;
  }
  .btn-gold-slide::before {
    content: '';
    position: absolute;
    top: 0; left: -100%; width: 100%; height: 100%;
    background: linear-gradient(90deg, transparent, rgba(212,175,55,0.15), transparent);
    transition: left 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);
    z-index: -1;
  }
  .btn-gold-slide:hover::before {
    left: 100%;
  }

  .order-step.active .step-icon {
    background-color: #D4AF37;
    color: #091A2E;
    box-shadow: 0 0 15px rgba(212, 175, 55, 0.4);
  }
  .order-step.active .step-line {
    background-color: #D4AF37;
  }
  
  ::-webkit-scrollbar { width: 8px; }
  ::-webkit-scrollbar-track { background: #F9F8F6; }
  ::-webkit-scrollbar-thumb { background: #C0C0C0; }
  ::-webkit-scrollbar-thumb:hover { background: #1A3A5C; }

html::-webkit-scrollbar, body::-webkit-scrollbar, *::-webkit-scrollbar {
    display: none !important; width: 0 !important; height: 0 !important;
  }
  html, body, * {
    -ms-overflow-style: none !important;
    scrollbar-width: none !important;
  }

